final class AppConfig {
    private final String env;
    private final java.util.List<String> servers;

    AppConfig(String env, java.util.List<String> servers) {
        this.env = env;
        this.servers = java.util.List.copyOf(servers);
    }

    String getEnv() {
        return env;
    }

    java.util.List<String> getServers() {
        return servers; // already unmodifiable snapshot
    }
}
